    parser.add_argument('--bootstrap_servers', required=True, help='Bootstrap servers for the Kafka cluster')
    parser.add_argument('--topic_name', required=True, help='Topic name')
    parser.add_argument('--num_partitions', type=int, help='Number of partitions')
    parser.add_argument('--replication_factor', type=int, help='Replication factor')
    parser.add_argument('--config', type=dict, help='Configuration for the topic')

    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_servers)

